import { GoogleGenAI } from "@google/genai";
import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * AI থেকে আসা টেক্সট থেকে JSON ব্লক খুঁজে বের করে পার্স করা।
   */
  extractJSON: (text: string | undefined) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * Gemini AI Call - acting as "Puter AI"
   * Improved to handle multi-turn contents and strictly follow SDK rules.
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string;
  }) => {
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey || apiKey === "undefined") {
        console.warn("API_KEY is missing or undefined.");
        throw new Error("API_KEY_MISSING");
      }

      const ai = new GoogleGenAI({ apiKey });

      let formattedContents: any;

      if (typeof params.contents === 'string') {
        formattedContents = params.contents;
      } else if (Array.isArray(params.contents)) {
        // Transform our internal message format to Gemini SDK format
        formattedContents = params.contents.map((msg: any) => ({
          role: msg.role === 'model' ? 'model' : 'user',
          parts: [{ text: msg.text || "" }]
        }));
      } else {
        formattedContents = params.contents;
      }

      const responsePromise = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: formattedContents,
        config: {
          systemInstruction: params.systemInstruction || `
            আপনার নাম "Puter AI"। আপনি রাজবাড়ী জেলার প্রধান ডিজিটাল অ্যাসিস্ট্যান্ট।
            আপনার কাজ হলো ট্রেনের লাইভ ডেটা বা স্ট্যাটিক শিডিউল ডেটা বিশ্লেষণ করে ব্যবহারকারীকে সহজ বাংলায় বুঝিয়ে বলা।
            যদি লাইভ এপিআই ডেটা অফলাইন হয়, তবে আপনি বর্তমান সময়ের সাপেক্ষে ট্রেনের শিডিউল চেক করে একটি সম্ভাব্য অবস্থান বলবেন।
            আপনার ভাষা হবে মার্জিত এবং বন্ধুত্বপূর্ণ।
          `,
          temperature: 0.7,
        },
      });

      // 15 second timeout for better user experience on slow networks
      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error("TIMEOUT")), 15000)
      );

      const response: any = await Promise.race([responsePromise, timeoutPromise]);

      if (!response || !response.text) {
        throw new Error("EMPTY_RESPONSE");
      }

      return {
        text: response.text,
        mode: 'puter_cloud_ai'
      };
    } catch (error: any) {
      console.error("AI Cloud Error:", error);
      // Return a specific mode to trigger local JS reasoning in the component
      return {
        text: null,
        mode: 'local_fallback',
        error: error.message
      };
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Sparkles, Trash2, AlertCircle, RefreshCcw, ShieldCheck, Globe, Zap } from 'lucide-react';
import { db } from '../db';

const SYSTEM_INSTRUCTION = `
আপনি হলেন "রাজবাড়ী জেলা তথ্য সহায়িকা – AI Chat Assistant"।
আপনার বৈশিষ্ট্য:
১. রাজবাড়ী জেলা সম্পর্কে সকল তথ্য প্রদান করা।
২. ভাষা: বাংলা।
৩. আপনি Puter.js AI নেটওয়ার্ক ব্যবহার করছেন।
৪. ডেভেলপার: Sovrab Roy।
৫. ব্যবহারকারীর প্রশ্নের উত্তর রাজবাড়ী জেলার প্রেক্ষাপটে দিন।
`;

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
}

const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী জেলা তথ্য সহায়িকা। জেমিনি এআই ব্যবহার করে আমি আপনাকে রাজবাড়ী সম্পর্কে যেকোনো তথ্য দিতে পারি। আজ আপনাকে কীভাবে সাহায্য করতে পারি?' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSend = async (retryText?: string) => {
    const userMessage = retryText || input.trim();
    if (!userMessage || isTyping) return;

    if (!retryText) {
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    }

    setIsTyping(true);

    try {
      // Create the history for the AI call
      const history = messages.map(m => ({ role: m.role, text: m.text }));
      history.push({ role: 'user', text: userMessage });

      const data = await db.callAI({
        contents: history,
        systemInstruction: SYSTEM_INSTRUCTION
      });

      if (data.mode === 'local_fallback' || !data.text) {
        throw new Error(data.error || "Connection failed");
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: data.text
      }]);
    } catch (error: any) {
      console.error("Chat Error:", error);
      let errorMsg = "দুঃখিত, বর্তমানে এআই সার্ভারের সাথে সংযোগ স্থাপন করা যাচ্ছে না। আপনার ইন্টারনেট সংযোগ বা এপিআই কী চেক করুন।";
      if (error.message === 'API_KEY_MISSING') {
        errorMsg = "অ্যাডমিন প্যানেল থেকে এপিআই কী (API_KEY) সেট করা হয়নি। অনুগ্রহ করে আপনার ডেভেলপার বা অ্যাডমিনের সাথে যোগাযোগ করুন।";
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: errorMsg, 
        isError: true 
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] animate-slide-up relative">
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
            <Sparkles className="w-5 h-5 fill-white" />
          </div>
          <div>
            <h3 className="font-black text-slate-800 dark:text-white leading-none text-sm uppercase">Puter Smart AI</h3>
            <div className="flex items-center gap-1.5 mt-1">
              <div className="flex items-center gap-1 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-tighter bg-emerald-100 text-emerald-600">
                <ShieldCheck className="w-2.5 h-2.5" />
                Live Network
              </div>
            </div>
          </div>
        </div>
        <button 
          onClick={() => setMessages([{ role: 'model', text: 'চ্যাট হিস্টোরি ক্লিয়ার করা হয়েছে। আমি আপনাকে রাজবাড়ী সম্পর্কে নতুনভাবে কীভাবে সাহায্য করতে পারি?' }])} 
          className="p-3 text-slate-400 hover:text-rose-500 rounded-xl transition-colors active:scale-90"
          title="Clear Chat"
        >
          <Trash2 className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-6 bg-slate-50 dark:bg-slate-950">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 shadow-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-800 text-indigo-600 border border-slate-100 dark:border-slate-800'}`}>
                {msg.role === 'user' ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
              </div>
              <div className="flex flex-col gap-2">
                <div className={`p-4 rounded-3xl text-sm leading-relaxed whitespace-pre-line shadow-sm border ${
                  msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none border-indigo-600' 
                  : msg.isError 
                    ? 'bg-rose-50 dark:bg-rose-950/30 text-rose-700 dark:text-rose-400 border-rose-200 dark:border-rose-900/50'
                    : 'bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-200 rounded-tl-none border-slate-100 dark:border-slate-800'
                }`}>
                  {msg.isError && <AlertCircle className="w-4 h-4 mb-2 inline-block mr-1" />}
                  {msg.text}
                </div>
                {msg.isError && (
                  <button 
                    onClick={() => handleSend([...messages].reverse().find(m => m.role === 'user')?.text)} 
                    className="flex items-center gap-2 text-[10px] font-black text-indigo-600 self-start px-4 py-2 bg-white dark:bg-slate-900 rounded-full border border-slate-100 dark:border-slate-800 shadow-sm active:scale-95 transition-all"
                  >
                    <RefreshCcw className="w-3 h-3" /> পুনরায় চেষ্টা
                  </button>
                )}
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start items-center gap-3">
            <div className="w-8 h-8 rounded-xl bg-white dark:bg-slate-800 flex items-center justify-center text-indigo-600 shadow-sm border border-slate-100 dark:border-slate-800"><Bot className="w-4 h-4" /></div>
            <div className="bg-white dark:bg-slate-900 px-4 py-3 rounded-2xl border border-slate-100 dark:border-slate-800 flex gap-1 shadow-sm">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-6 bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-800">
        <div className="flex gap-3 bg-slate-50 dark:bg-slate-900 p-2 rounded-[2rem] border border-slate-200 dark:border-slate-800 focus-within:border-indigo-400 transition-all shadow-inner">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="রাজবাড়ী সম্পর্কে জিজ্ঞাসা করুন..." 
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-4 text-slate-800 dark:text-white"
          />
          <button 
            onClick={() => handleSend()}
            disabled={!input.trim() || isTyping}
            className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
              !input.trim() || isTyping ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 text-white shadow-lg active:scale-90 hover:bg-indigo-700'
            }`}
          >
            {isTyping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>
        <p className="text-[8px] text-center mt-3 text-slate-400 font-bold uppercase tracking-widest opacity-60">Powered by Gemini Pro & Puter.js</p>
      </div>
    </div>
  );
};

export default AIChat;

import React, { useState } from 'react';
import { 
  ShieldCheck, 
  Activity, 
  Cloud,
  Zap,
  LogOut,
  PlayCircle,
  CheckCircle2,
  XCircle,
  Loader2,
  Globe,
  Sparkles,
  Server,
  AlertTriangle
} from 'lucide-react';
import { db } from '../db';

interface AdminPanelProps {
  onLogout: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogout }) => {
  const [testStatus, setTestStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [testResult, setTestResult] = useState('');

  const runDiagnostics = async () => {
    setTestStatus('loading');
    setTestResult('');
    try {
      const response = await db.callAI({
        contents: "Hello, system check. Are you online?",
        systemInstruction: "You are a diagnostic tool. Reply with exactly: 'SYSTEM_ONLINE'"
      });

      if (response.mode === 'local_fallback' || !response.text) {
        throw new Error("Local fallback triggered. Check API key.");
      }

      setTestStatus('success');
      setTestResult(`জেমিনি এআই সফলভাবে সংযুক্ত হয়েছে! রেসপন্স মোড: ${response.mode}`);
    } catch (e: any) {
      console.error("Diagnostic Error:", e);
      setTestStatus('error');
      setTestResult(e.message === 'API_KEY_MISSING' 
        ? "API Key পাওয়া যায়নি। অনুগ্রহ করে এনভায়রনমেন্ট ভেরিয়েবল (API_KEY) চেক করুন।" 
        : `সংযোগে ত্রুটি: ${e.message || "Unknown error"}. এটি নেটওয়ার্ক বা কোটা সমস্যা হতে পারে।`);
    }
  };

  return (
    <div className="p-6 animate-slide-up pb-32 max-w-lg mx-auto">
      <div className="mb-8 p-8 bg-gradient-to-br from-slate-900 to-indigo-900 rounded-[3.5rem] text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-10 opacity-10">
          <Activity className="w-24 h-24 animate-pulse" />
        </div>
        <div className="relative z-10 flex justify-between items-start">
          <div className="flex items-center gap-4">
            <div className="bg-white/10 p-3 rounded-2xl backdrop-blur-md border border-white/20">
              <ShieldCheck className="w-6 h-6 text-emerald-400" />
            </div>
            <div>
              <h2 className="text-2xl font-black uppercase tracking-tight">সিস্টেম কন্ট্রোল</h2>
              <p className="text-indigo-200 text-[10px] font-bold opacity-80 uppercase tracking-[0.3em]">Smart Engine Dashboard</p>
            </div>
          </div>
          <button onClick={onLogout} className="p-3 bg-white/10 hover:bg-white/20 rounded-2xl border border-white/20 transition-all text-white"><LogOut className="w-5 h-5" /></button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 p-8 rounded-[3rem] border border-slate-100 dark:border-slate-800 premium-shadow mb-8">
        <div className="flex items-center gap-4 mb-6">
          <div className="p-4 bg-indigo-600 text-white rounded-2xl shadow-lg"><Server className="w-6 h-6" /></div>
          <div>
            <h4 className="text-xl font-black dark:text-white tracking-tighter uppercase">সার্ভার স্ট্যাটাস</h4>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Gemini API Diagnostic</p>
          </div>
        </div>

        <button 
          onClick={runDiagnostics}
          disabled={testStatus === 'loading'}
          className="w-full flex items-center justify-center gap-3 py-5 bg-indigo-600 text-white rounded-[1.8rem] font-black shadow-xl hover:bg-indigo-700 active:scale-95 transition-all mb-6 disabled:opacity-50"
        >
          {testStatus === 'loading' ? <Loader2 className="w-5 h-5 animate-spin" /> : <Zap className="w-5 h-5" />}
          {testStatus === 'loading' ? 'কানেকশন টেস্ট হচ্ছে...' : 'জেমিনি কানেকশন টেস্ট করুন'}
        </button>

        {testStatus !== 'idle' && (
          <div className={`p-6 rounded-[2rem] border flex items-start gap-4 animate-slide-up ${
            testStatus === 'success' ? 'bg-emerald-50 border-emerald-100 text-emerald-700 dark:bg-emerald-950/20 dark:border-emerald-900/50' : 
            testStatus === 'error' ? 'bg-rose-50 border-rose-100 text-rose-700 dark:bg-rose-950/20 dark:border-rose-900/50' : 'bg-slate-50 border-slate-100 text-slate-600 dark:bg-slate-800/50 dark:border-slate-800'
          }`}>
            {testStatus === 'success' ? <CheckCircle2 className="w-6 h-6 shrink-0 mt-1" /> : <AlertTriangle className="w-6 h-6 shrink-0 mt-1" />}
            <div>
              <p className="font-black text-sm uppercase tracking-widest mb-1">{testStatus === 'success' ? 'জেমিনি অনলাইন' : 'জেমিনি অফলাইন'}</p>
              <p className="text-xs font-medium leading-relaxed opacity-90">{testResult}</p>
            </div>
          </div>
        )}
      </div>

      <div className="bg-amber-50 dark:bg-amber-950/20 p-6 rounded-[2.5rem] border border-amber-100 dark:border-amber-900/50 flex items-start gap-4">
          <Globe className="w-8 h-8 text-amber-500 shrink-0" />
          <div className="space-y-2">
            <p className="text-[10px] font-black text-amber-800 dark:text-amber-400 uppercase tracking-widest">গুরুত্বপূর্ণ টিপস</p>
            <p className="text-xs font-bold text-amber-700 dark:text-amber-500 leading-relaxed">
              যদি আপনার API Key সেট করা থাকে কিন্তু তবুও "অফলাইন" দেখায়, তবে নিশ্চিত হোন যে আপনার এপিআই কী-তে পর্যাপ্ত কোটা আছে এবং এটি `gemini-3-flash-preview` মডেল সাপোর্ট করে।
            </p>
          </div>
      </div>
    </div>
  );
};

export default AdminPanel;

import { GoogleGenAI } from "@google/genai";
import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * AI থেকে আসা টেক্সট থেকে JSON ব্লক খুঁজে বের করে পার্স করা।
   */
  extractJSON: (text: string | undefined) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * Gemini AI Call - acting as "Puter AI"
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string;
    useSearch?: boolean;
  }) => {
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey || apiKey === "undefined") {
        console.warn("API_KEY is missing or undefined.");
        throw new Error("API_KEY_MISSING");
      }

      const ai = new GoogleGenAI({ apiKey });

      let formattedContents: any;

      if (typeof params.contents === 'string') {
        formattedContents = params.contents;
      } else if (Array.isArray(params.contents)) {
        formattedContents = params.contents.map((msg: any) => ({
          role: msg.role === 'model' ? 'model' : 'user',
          parts: [{ text: msg.text || "" }]
        }));
      } else {
        formattedContents = params.contents;
      }

      const responsePromise = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: formattedContents,
        config: {
          systemInstruction: params.systemInstruction || `
            আপনার নাম "Puter AI"। আপনি রাজবাড়ী জেলার প্রধান ডিজিটাল অ্যাসিস্ট্যান্ট।
            আপনার কাজ হলো ট্রেনের লাইভ ডেটা বা স্ট্যাটিক শিডিউল ডেটা বিশ্লেষণ করে ব্যবহারকারীকে সহজ বাংলায় বুঝিয়ে বলা।
          `,
          tools: params.useSearch ? [{ googleSearch: {} }] : undefined,
          temperature: 0.2,
        },
      });

      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error("TIMEOUT")), 20000)
      );

      const response: any = await Promise.race([responsePromise, timeoutPromise]);

      if (!response || !response.text) {
        throw new Error("EMPTY_RESPONSE");
      }

      return {
        text: response.text,
        mode: params.useSearch ? 'google_search_grounding' : 'puter_cloud_ai',
        groundingMetadata: response.candidates?.[0]?.groundingMetadata
      };
    } catch (error: any) {
      console.error("AI Cloud Error:", error);
      return {
        text: null,
        mode: 'local_fallback',
        error: error.message
      };
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

