import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Loader2, 
  TrainFront,
  X,
  Sparkles,
  Info,
  RefreshCcw,
  AlertCircle,
  Clock,
  Globe,
  Activity,
  Zap,
  MessageCircle,
  Navigation2,
  Cpu,
  Facebook,
  ShoppingBasket,
  Megaphone,
