    setTestStatus('loading');
    setTestResult('');
    try {
      const response = await db.callAI({
        contents: "Hello, system check. Are you online?",
        systemInstruction: "You are a diagnostic tool. Reply with exactly: 'SYSTEM_ONLINE'"
      });

      if (response.mode === 'local_fallback' || !response.text) {
        throw new Error("Local fallback triggered. Check API key.");
      }

      setTestStatus('success');
      setTestResult(`অভিনন্দন! আপনার জেমিনি এআই (Gemini AI) এখন পুরোপুরি সক্রিয়। রেসপন্স মোড: ${response.mode}. এখন আপনার অ্যাপটি ২০২৬ সালের রিয়েল-টাইম তথ্য ও লাইভ ট্রেন ট্র্যাকিং সাপোর্ট করবে।`);
    } catch (e: any) {
      console.error("Diagnostic Error:", e);
      setTestStatus('error');
      setTestResult(e.message === 'API_KEY_MISSING' 
        ? "ত্রুটি: API Key খুঁজে পাওয়া যায়নি। আপনি যে এপিআই কী-টি তৈরি করেছেন সেটি হোস্টিং সেটিংস-এ API_KEY নামে সেট করেছেন তো? একবার চেক করে নিন।" 
        : `সংযোগে ত্রুটি: ${e.message || "Unknown error"}. এটি আপনার এপিআই কোটা লিমিট শেষ হওয়া বা নেটওয়ার্ক সমস্যার কারণে হতে পারে।`);
