            <div>
              <p className="font-black text-sm uppercase tracking-widest mb-1">{testStatus === 'success' ? 'জেমিনি অনলাইন' : 'জেমিনি অফলাইন'}</p>
              <p className="text-xs font-medium leading-relaxed opacity-90">{testResult}</p>
            </div>
          </div>
        )}
      </div>

      <div className="bg-amber-50 dark:bg-amber-950/20 p-8 rounded-[3rem] border border-amber-100 dark:border-amber-900/50 flex flex-col gap-4">
          <div className="flex items-center gap-3 text-amber-600">
            <Key className="w-6 h-6" />
            <p className="text-[11px] font-black uppercase tracking-widest">কীভাবে কী সেট করবেন?</p>
          </div>
          <p className="text-xs font-bold text-amber-700 dark:text-amber-500 leading-relaxed">
            ১. আপনার স্ক্রিনশটের <strong className="text-slate-900 dark:text-white">Copy Key</strong> বাটনে ক্লিক করুন।<br/>
            ২. আপনার প্রোজেক্ট ড্যাশবোর্ডে গিয়ে Environment Variable সেকশনে <strong className="text-slate-900 dark:text-white">API_KEY</strong> ভেরিয়েবলে এটি পেস্ট করুন।<br/>
            ৩. এরপর প্রোজেক্টটি রি-ডিপ্লয় করলেই সবকিছু সচল হয়ে যাবে!
          </p>
      </div>
    </div>
  );
