import { GoogleGenAI } from "@google/genai";
import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  extractJSON: (text: string | undefined) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string;
    useSearch?: boolean;
  }) => {
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey || apiKey === "undefined" || apiKey === "") {
        throw new Error("API_KEY_MISSING");
      }

      const ai = new GoogleGenAI({ apiKey });

      let formattedContents: any[];
      if (typeof params.contents === 'string') {
        formattedContents = [{ role: 'user', parts: [{ text: params.contents }] }];
      } else if (Array.isArray(params.contents)) {
        formattedContents = params.contents.map((msg: any) => ({
          role: msg.role === 'model' ? 'model' : 'user',
          parts: [{ text: msg.text || "" }]
        }));
      } else {
        formattedContents = [params.contents];
      }

      const enhancedSystemInstruction = params.systemInstruction || `
        আপনি "Puter AI", রাজবাড়ী জেলার ডিজিটাল অ্যাসিস্ট্যান্ট।
        ডেভেলপার: **SOVRAB ROY**।
        ১. ট্রেনের লাইভ লোকেশন জানতে Google Search ব্যবহার করুন। 
        ২. ফেসবুক গ্রুপ (যেমন: Rajbari Train Tracking Group) থেকে ২০২৬ সালের লেটেস্ট পোস্টের তথ্য দিন।
        ৩. উত্তর সবসময় শুদ্ধ বাংলায় দিন।
      `;

      const modelName = 'gemini-3-flash-preview';

      const responsePromise = ai.models.generateContent({
        model: modelName,
        contents: formattedContents,
        config: {
          systemInstruction: enhancedSystemInstruction,
          tools: params.useSearch ? [{ googleSearch: {} }] : undefined,
          temperature: 0.1,
        },
      });

      // Quick timeout for real-time feel
      const timeoutLimit = params.useSearch ? 30000 : 15000;
      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error("TIMEOUT")), timeoutLimit)
      );

      const response: any = await Promise.race([responsePromise, timeoutPromise]);

      if (!response || !response.text) {
        throw new Error("EMPTY_RESPONSE");
      }

      return {
        text: response.text,
        mode: params.useSearch ? 'gemini_cloud_live' : 'puter_cloud_ai',
        groundingMetadata: response.candidates?.[0]?.groundingMetadata
      };
    } catch (error: any) {
      console.error("AI Cloud Error:", error.message);

      // Map specific error messages
      let errorType = 'GENERIC_ERROR';
      if (error.message?.includes('429')) errorType = 'QUOTA_EXCEEDED';
      if (error.message === 'TIMEOUT') errorType = 'TIMEOUT';

      return {
        text: null,
        mode: 'local_fallback',
        error: errorType
      };
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Sparkles, Trash2, AlertCircle, RefreshCcw, ShieldCheck, Globe, Zap, Cpu, MapPin, Phone, TrainFront } from 'lucide-react';
