const SYSTEM_INSTRUCTION = `
আপনি হলেন "রাজবাড়ী জেলা তথ্য সহায়িকা – AI Chat Assistant"।
আপনার বিশেষ পরিচয়:
১. এই সম্পূর্ণ অ্যাপ্লিকেশন এবং আপনাকে ডেভেলপ করেছেন এক্সপার্ট সফটওয়্যার ইঞ্জিনিয়ার **SOVRAB ROY** (সৌরভ রায়)। 
২. আপনার মূল লক্ষ্য রাজবাড়ী জেলা সম্পর্কে নির্ভুল তথ্য প্রদান করা।
৩. ভাষা: বাংলা।
৪. আপনি জেমিনি এআই (Gemini AI) নেটওয়ার্ক ব্যবহার করছেন।
`;

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
  mode?: 'gemini' | 'puter';
  localData?: any[];
}

const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী জেলা তথ্য সহায়িকা। জেমিনি এআই ব্যবহার করে আমি আপনাকে রাজবাড়ী সম্পর্কে যেকোনো তথ্য দিতে পারি। আজ আপনাকে কীভাবে সাহায্য করতে পারি?', mode: 'gemini' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  // Puter Local Search Engine Logic
  const runPuterLocalSearch = (query: string): { text: string; data: any[] } => {
    const q = query.toLowerCase();
    let results: any[] = [];
    let responseText = "দুঃখিত, জেমিনি এআই অফলাইন এবং আপনার প্রশ্নের কোনো সরাসরি উত্তর লোকাল ডাটাবেসে পাওয়া যায়নি।";

    // Keyword matching logic
    if (q.includes('ডাক্তার') || q.includes('doctor')) {
      results = RAJBARI_DATA.doctors;
      responseText = "সিস্টেম নোট: জেমিনি অফলাইন। পুটার ইঞ্জিন রাজবাড়ী জেলার ডাক্তারদের তালিকা খুঁজে পেয়েছে:";
    } else if (q.includes('ট্রেন') || q.includes('train')) {
      results = RAJBARI_DATA.trains;
      responseText = "সিস্টেম নোট: জেমিনি অফলাইন। পুটার ইঞ্জিন রাজবাড়ী রেলওয়ে স্টেশনের ট্রেনের সময়সূচী খুঁজে পেয়েছে:";
    } else if (q.includes('জরুরি') || q.includes('পুলিশ') || q.includes('হেল্পলাইন')) {
      results = RAJBARI_DATA.emergency;
      responseText = "সিস্টেম নোট: পুটার ইঞ্জিন রাজবাড়ীর জরুরি নম্বরগুলো খুঁজে পেয়েছে:";
    } else if (q.includes('হাসপাতাল') || q.includes('hospital')) {
      results = RAJBARI_DATA.hospitals;
      responseText = "সিস্টেম নোট: রাজবাড়ীর প্রধান হাসপাতালগুলোর তালিকা দেওয়া হলো:";
    } else if (q.includes('বাজার') || q.includes('দাম') || q.includes('price')) {
      results = RAJBARI_DATA.market_price;
      responseText = "সিস্টেম নোট: আজকের সম্ভাব্য বাজারদর (লোকাল ডাটা):";
    } else if (q.includes('হাই') || q.includes('হ্যালো') || q.includes('কেমন আছ')) {
      responseText = "হ্যালো! আমি রাজবাড়ী জেলা তথ্য সহায়িকা (অফলাইন মোড)। জেমিনি এআই বর্তমানে কাজ করছে না, তবে আমি আপনাকে রাজবাড়ীর লোকাল ডাটাবেস থেকে তথ্য দিতে পারি। ডাক্তার, ট্রেন বা জরুরি নম্বর জানতে প্রশ্ন করুন।";
    }

    return { text: responseText, data: results };
  };

  const handleSend = async (retryText?: string) => {
    const userMessage = retryText || input.trim();
    if (!userMessage || isTyping) return;

    if (!retryText) {
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    }

    setIsTyping(true);

    try {
      const history = messages.map(m => ({ role: m.role, text: m.text }));
      history.push({ role: 'user', text: userMessage });

      const data = await db.callAI({
        contents: history,
        systemInstruction: SYSTEM_INSTRUCTION
      });

      if (data.mode === 'local_fallback' || !data.text) {
        throw new Error("SERVER_UNAVAILABLE");
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: data.text,
        mode: 'gemini'
      }]);
    } catch (error: any) {
      console.warn("Gemini Failed. Engaging Puter Engine...");
      const puterResponse = runPuterLocalSearch(userMessage);

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: puterResponse.text, 
        mode: 'puter',
        localData: puterResponse.data,
        isError: false
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  const formatText = (text: string) => {
    return text.split('**').map((part, i) => i % 2 === 1 ? <strong key={i} className="font-black text-slate-900 dark:text-white">{part}</strong> : part);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] animate-slide-up relative">
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
            <Sparkles className="w-5 h-5 fill-white" />
          </div>
          <div>
            <h3 className="font-black text-slate-800 dark:text-white leading-none text-sm uppercase tracking-tight">Rajbari Smart AI</h3>
            <div className="flex items-center gap-1.5 mt-1">
              <div className="flex items-center gap-1 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-tighter bg-emerald-100 text-emerald-600 shadow-sm">
                <Globe className="w-2.5 h-2.5" />
                Live Engine
              </div>
            </div>
          </div>
        </div>
        <button 
          onClick={() => setMessages([{ role: 'model', text: 'চ্যাট হিস্টোরি ক্লিয়ার করা হয়েছে। আমি আপনাকে রাজবাড়ী সম্পর্কে নতুনভাবে কীভাবে সাহায্য করতে পারি?', mode: 'gemini' }])} 
          className="p-3 text-slate-400 hover:text-rose-500 rounded-xl transition-colors active:scale-90"
        >
          <Trash2 className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-8 bg-slate-50 dark:bg-slate-950">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 shadow-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-800 text-indigo-600 border border-slate-100 dark:border-slate-800'}`}>
                {msg.role === 'user' ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
              </div>
              <div className="flex flex-col gap-1.5">
                {msg.role === 'model' && (
                   <span className={`text-[8px] font-black uppercase tracking-widest flex items-center gap-1 mb-1 px-2 py-0.5 rounded-full w-fit ${msg.mode === 'gemini' ? 'bg-indigo-50 text-indigo-500' : 'bg-amber-100 text-amber-600'}`}>
                     {msg.mode === 'gemini' ? <Sparkles className="w-2 h-2" /> : <Cpu className="w-2 h-2" />}
                     {msg.mode === 'gemini' ? 'Gemini AI' : 'Puter Engine (Active)'}
                   </span>
                )}
                <div className={`p-4 rounded-[1.8rem] text-sm leading-relaxed whitespace-pre-line shadow-sm border ${
                  msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none border-indigo-600' 
                  : msg.mode === 'puter' 
                    ? 'bg-amber-50 dark:bg-amber-950/20 text-amber-900 dark:text-amber-200 border-amber-200 dark:border-amber-900 rounded-tl-none'
                    : 'bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-200 rounded-tl-none border-slate-100 dark:border-slate-800'
                }`}>
