import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Sparkles, Trash2, AlertCircle, RefreshCcw, ShieldCheck, Globe, Zap, Cpu, MapPin, Phone, TrainFront, Code2, Heart } from 'lucide-react';
import { db } from '../db';
import { RAJBARI_DATA } from '../constants.tsx';

const SYSTEM_INSTRUCTION = `
আপনি হলেন "রাজবাড়ী জেলা তথ্য সহায়িকা – AI Chat Assistant"।
আপনার বিশেষ পরিচয়:
১. এই সম্পূর্ণ অ্যাপ্লিকেশন এবং আপনাকে ডেভেলপ করেছেন এক্সপার্ট সফটওয়্যার ইঞ্জিনিয়ার **SOVRAB ROY** (সৌরভ রায়)। 
২. আপনার মূল লক্ষ্য রাজবাড়ী জেলা সম্পর্কে নির্ভুল তথ্য প্রদান করা।
৩. ভাষা: বাংলা।
৪. আপনি জেমিনি এআই (Gemini AI) নেটওয়ার্ক ব্যবহার করছেন।
`;

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
  mode?: 'gemini' | 'puter';
  localData?: any[];
}

const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী জেলা তথ্য সহায়িকা। জেমিনি এআই ব্যবহার করে আমি আপনাকে রাজবাড়ী সম্পর্কে যেকোনো তথ্য দিতে পারি। আজ আপনাকে কীভাবে সাহায্য করতে পারি?', mode: 'gemini' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  // Expanded Puter Local Search Engine
  const runPuterLocalSearch = (query: string): { text: string; data: any[] } => {
    const q = query.toLowerCase();
    let results: any[] = [];
    let responseText = "";

    // 1. Developer Check (Critical Fix for user request)
    if (q.includes('developer') || q.includes('ডেভেলপার') || q.includes('sovrab') || q.includes('সৌরভ') || q.includes('তৈরি') || q.includes('বানিয়েছে')) {
      responseText = "সিস্টেম নোট (Puter Engine): এই স্মার্ট পোর্টালটি এবং আমাকে (AI) ডেভেলপ করেছেন রাজবাড়ীর গর্বিত সন্তান, এক্সপার্ট সফটওয়্যার ইঞ্জিনিয়ার **SOVRAB ROY** (সৌরভ রায়)। তিনি মূলত জাভাস্ক্রিপ্ট এবং এআই সল্যুশন নিয়ে কাজ করেন।";
    } 
    // 2. Train Check
    else if (q.includes('ট্রেন') || q.includes('train') || q.includes('গাড়ি')) {
      results = RAJBARI_DATA.trains;
      responseText = "সিস্টেম নোট: জেমিনি এআই বর্তমানে সংযোগ বিচ্ছিন্ন। পুটার ইঞ্জিন রাজবাড়ী রেলওয়ে স্টেশনের অফিসিয়াল সময়সূচী খুঁজে পেয়েছে:";
    } 
    // 3. Doctor Check
    else if (q.includes('ডাক্তার') || q.includes('doctor') || q.includes('চিকিৎসক')) {
      results = RAJBARI_DATA.doctors;
      responseText = "সিস্টেম নোট: বর্তমানে পুটার অফলাইন ইঞ্জিন কাজ করছে। রাজবাড়ীর বিশেষজ্ঞ ডাক্তারদের তালিকা নিচে দেওয়া হলো:";
    } 
    // 4. Emergency Check
    else if (q.includes('জরুরি') || q.includes('পুলিশ') || q.includes('ফায়ার') || q.includes('emergency')) {
      results = RAJBARI_DATA.emergency;
      responseText = "সিস্টেম নোট: রাজবাড়ী জেলার সকল জরুরি হেল্পলাইন নম্বরগুলো এখানে দেখুন:";
    }
    // 5. Hospital Check
    else if (q.includes('হাসপাতাল') || q.includes('hospital') || q.includes('ক্লিনিক')) {
      results = RAJBARI_DATA.hospitals;
      responseText = "সিস্টেম নোট: রাজবাড়ীর প্রধান হাসপাতাল ও স্বাস্থ্য কমপ্লেক্সগুলোর তথ্য:";
    }
    // 6. District Info
    else if (q.includes('রাজবাড়ী') || q.includes('rajbari') || q.includes('জেলা')) {
      responseText = "রাজবাড়ী জেলা বাংলাদেশের ঢাকা বিভাগের একটি প্রশাসনিক অঞ্চল। এটি পদ্মা নদীর তীরে অবস্থিত এবং সাহিত্যিক মীর মশাররফ হোসেনের জন্মস্থান হিসেবে এটি বিখ্যাত। বর্তমানে এটি একটি উদীয়মান স্মার্ট জেলা।";
    }
    // 7. Greetings
    else if (q.includes('হাই') || q.includes('হ্যালো') || q.includes('কেমন আছ') || q.includes('hi') || q.includes('hello')) {
      responseText = "হ্যালো! আমি রাজবাড়ী স্মার্ট এআই-এর পুটার ইঞ্জিন। বর্তমানে জেমিনি এআই-এর সাথে সংযোগ না থাকায় আমি লিমিটেড মোডে কাজ করছি। আপনি কি রাজবাড়ীর ট্রেন, ডাক্তার বা জরুরি কোনো তথ্য খুঁজছেন?";
    }
    // 8. Fallback (If nothing matches)
    else {
      responseText = "দুঃখিত, জেমিনি এআই সংযোগ বিচ্ছিন্ন এবং আপনার প্রশ্নের কোনো সরাসরি উত্তর আমার লোকাল ডাটাবেসে নেই। তবে আমি আপনাকে নিচের বিষয়গুলোতে সাহায্য করতে পারি:\n\n• **ট্রেন সময়সূচী** (লিখুন: ট্রেন)\n• **ডাক্তার তালিকা** (লিখুন: ডাক্তার)\n• **জরুরি নম্বর** (লিখুন: হেল্পলাইন)\n• **বাজারদর** (লিখুন: বাজারদর)";
    }

    return { text: responseText, data: results };
  };

  const handleSend = async (retryText?: string) => {
    const userMessage = retryText || input.trim();
    if (!userMessage || isTyping) return;

    if (!retryText) {
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    }

    setIsTyping(true);

    try {
      const history = messages.map(m => ({ role: m.role, text: m.text }));
      history.push({ role: 'user', text: userMessage });

      const data = await db.callAI({
        contents: history,
        systemInstruction: SYSTEM_INSTRUCTION
      });

      if (data.mode === 'local_fallback' || !data.text) {
        throw new Error("SERVER_UNAVAILABLE");
      }

      setMessages(prev => [...prev, { role: 'model', text: data.text, mode: 'gemini' }]);
    } catch (error: any) {
      console.warn("Gemini Failed. Puter Logic Engaging...");
      const puterResponse = runPuterLocalSearch(userMessage);

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: puterResponse.text, 
        mode: 'puter',
        localData: puterResponse.data
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  const formatText = (text: string) => {
    return text.split('**').map((part, i) => i % 2 === 1 ? <strong key={i} className="font-black text-slate-900 dark:text-white">{part}</strong> : part);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] animate-slide-up relative">
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
            <Sparkles className="w-5 h-5 fill-white" />
          </div>
          <div>
            <h3 className="font-black text-slate-800 dark:text-white leading-none text-sm uppercase tracking-tight">Rajbari Smart AI</h3>
            <div className="flex items-center gap-1.5 mt-1">
              <div className="flex items-center gap-1 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-tighter bg-emerald-100 text-emerald-600 shadow-sm">
                <Globe className="w-2.5 h-2.5" />
                Live Engine
              </div>
            </div>
          </div>
        </div>
        <button 
          onClick={() => setMessages([{ role: 'model', text: 'চ্যাট হিস্টোরি ক্লিয়ার করা হয়েছে। আমি আপনাকে রাজবাড়ী সম্পর্কে নতুনভাবে কীভাবে সাহায্য করতে পারি?', mode: 'gemini' }])} 
          className="p-3 text-slate-400 hover:text-rose-500 rounded-xl transition-colors active:scale-90"
        >
          <Trash2 className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-8 bg-slate-50 dark:bg-slate-950">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[92%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 shadow-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-800 text-indigo-600 border border-slate-100 dark:border-slate-800'}`}>
                {msg.role === 'user' ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
              </div>
              <div className="flex flex-col gap-1.5">
                {msg.role === 'model' && (
                   <span className={`text-[8px] font-black uppercase tracking-widest flex items-center gap-1 mb-1 px-2 py-0.5 rounded-full w-fit ${msg.mode === 'gemini' ? 'bg-indigo-50 text-indigo-500' : 'bg-amber-100 text-amber-600'}`}>
                     {msg.mode === 'gemini' ? <Sparkles className="w-2 h-2" /> : <Cpu className="w-2 h-2" />}
                     {msg.mode === 'gemini' ? 'Gemini AI Online' : 'Puter Local Engine'}
                   </span>
                )}
                <div className={`p-4 rounded-[1.8rem] text-sm leading-relaxed whitespace-pre-line shadow-sm border ${
                  msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none border-indigo-600' 
                  : msg.mode === 'puter' 
                    ? 'bg-amber-50 dark:bg-amber-950/20 text-amber-900 dark:text-amber-200 border-amber-200 dark:border-amber-900 rounded-tl-none'
                    : 'bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-200 rounded-tl-none border-slate-100 dark:border-slate-800'
                }`}>
                  {formatText(msg.text)}

                  {msg.localData && msg.localData.length > 0 && (
                    <div className="mt-4 space-y-2">
                      {msg.localData.slice(0, 4).map((item, i) => (
                        <div key={i} className="bg-white/50 dark:bg-black/20 p-3 rounded-xl border border-white/20 flex justify-between items-center transition-all active:scale-95">
                          <div className="flex items-center gap-2">
                            {item.route ? <TrainFront className="w-3.5 h-3.5 text-indigo-600" /> : <User className="w-3.5 h-3.5 text-indigo-600" />}
                            <div className="flex flex-col">
                                <span className="text-[11px] font-black text-slate-800 dark:text-white">{item.name}</span>
                                <span className="text-[8px] text-slate-400 font-bold uppercase">{item.specialty || item.route || item.type}</span>
                            </div>
                          </div>
                          {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><Phone className="w-3.5 h-3.5" /></a>}
                        </div>
                      ))}
                      <p className="text-[9px] opacity-60 italic text-center mt-2 font-bold uppercase tracking-widest flex items-center justify-center gap-2">
                         <Info className="w-3 h-3" /> More data in Main Menu
                      </p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start items-center gap-3">
            <div className="w-8 h-8 rounded-xl bg-white dark:bg-slate-800 flex items-center justify-center text-indigo-600 shadow-sm border border-slate-100 dark:border-slate-800"><Bot className="w-4 h-4" /></div>
            <div className="bg-white dark:bg-slate-900 px-4 py-3 rounded-2xl border border-slate-100 dark:border-slate-800 flex gap-1 shadow-sm">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-6 bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-800">
        <div className="flex gap-3 bg-slate-50 dark:bg-slate-900 p-2 rounded-[2rem] border border-slate-200 dark:border-slate-800 focus-within:border-indigo-400 transition-all shadow-inner">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="রাজবাড়ী সম্পর্কে জিজ্ঞাসা করুন..." 
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-4 text-slate-800 dark:text-white"
          />
          <button 
            onClick={() => handleSend()}
            disabled={!input.trim() || isTyping}
            className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
              !input.trim() || isTyping ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 text-white shadow-lg active:scale-90 hover:bg-indigo-700'
            }`}
          >
            {isTyping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>
        <div className="mt-3 flex items-center justify-center gap-2 opacity-30">
           <Heart className="w-3 h-3 text-rose-500 fill-rose-500" />
           <span className="text-[8px] font-black uppercase tracking-[0.4em]">Designed for Rajbari</span>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import React, { useState, useRef, useEffect } from 'react';
/* Added Info icon to imports */
import { Send, Bot, User, Loader2, Sparkles, Trash2, AlertCircle, RefreshCcw, ShieldCheck, Globe, Zap, Cpu, MapPin, Phone, TrainFront, Code2, Heart, Info } from 'lucide-react';
import { db } from '../db';
import { RAJBARI_DATA } from '../constants.tsx';

const SYSTEM_INSTRUCTION = `
আপনি হলেন "রাজবাড়ী জেলা তথ্য সহায়িকা – AI Chat Assistant"।
আপনার বিশেষ পরিচয়:
১. এই সম্পূর্ণ অ্যাপ্লিকেশন এবং আপনাকে ডেভেলপ করেছেন এক্সপার্ট সফটওয়্যার ইঞ্জিনিয়ার **SOVRAB ROY** (সৌরভ রায়)। 
২. আপনার মূল লক্ষ্য রাজবাড়ী জেলা সম্পর্কে নির্ভুল তথ্য প্রদান করা।
৩. ভাষা: বাংলা।
৪. আপনি জেমিনি এআই (Gemini AI) নেটওয়ার্ক ব্যবহার করছেন।
`;

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
  mode?: 'gemini' | 'puter';
  localData?: any[];
}

const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী জেলা তথ্য সহায়িকা। জেমিনি এআই ব্যবহার করে আমি আপনাকে রাজবাড়ী সম্পর্কে যেকোনো তথ্য দিতে পারি। আজ আপনাকে কীভাবে সাহায্য করতে পারি?', mode: 'gemini' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  // Expanded Puter Local Search Engine
  const runPuterLocalSearch = (query: string): { text: string; data: any[] } => {
    const q = query.toLowerCase();
    let results: any[] = [];
    let responseText = "";

    // 1. Developer Check (Critical Fix for user request)
    if (q.includes('developer') || q.includes('ডেভেলপার') || q.includes('sovrab') || q.includes('সৌরভ') || q.includes('তৈরি') || q.includes('বানিয়েছে')) {
      responseText = "সিস্টেম নোট (Puter Engine): এই স্মার্ট পোর্টালটি এবং আমাকে (AI) ডেভেলপ করেছেন রাজবাড়ীর গর্বিত সন্তান, এক্সপার্ট সফটওয়্যার ইঞ্জিনিয়ার **SOVRAB ROY** (সৌরভ রায়)। তিনি মূলত জাভাস্ক্রিপ্ট এবং এআই সল্যুশন নিয়ে কাজ করেন।";
    } 
    // 2. Train Check
    else if (q.includes('ট্রেন') || q.includes('train') || q.includes('গাড়ি')) {
      results = RAJBARI_DATA.trains;
      responseText = "সিস্টেম নোট: জেমিনি এআই বর্তমানে সংযোগ বিচ্ছিন্ন। পুটার ইঞ্জিন রাজবাড়ী রেলওয়ে স্টেশনের অফিসিয়াল সময়সূচী খুঁজে পেয়েছে:";
    } 
    // 3. Doctor Check
    else if (q.includes('ডাক্তার') || q.includes('doctor') || q.includes('চিকিৎসক')) {
      results = RAJBARI_DATA.doctors;
      responseText = "সিস্টেম নোট: বর্তমানে পুটার অফলাইন ইঞ্জিন কাজ করছে। রাজবাড়ীর বিশেষজ্ঞ ডাক্তারদের তালিকা নিচে দেওয়া হলো:";
    } 
    // 4. Emergency Check
    else if (q.includes('জরুরি') || q.includes('পুলিশ') || q.includes('ফায়ার') || q.includes('emergency')) {
      results = RAJBARI_DATA.emergency;
      responseText = "সিস্টেম নোট: রাজবাড়ী জেলার সকল জরুরি হেল্পলাইন নম্বরগুলো এখানে দেখুন:";
    }
    // 5. Hospital Check
    else if (q.includes('হাসপাতাল') || q.includes('hospital') || q.includes('ক্লিনিক')) {
      results = RAJBARI_DATA.hospitals;
      responseText = "সিস্টেম নোট: রাজবাড়ীর প্রধান হাসপাতাল ও স্বাস্থ্য কমপ্লেক্সগুলোর তথ্য:";
    }
    // 6. District Info
    else if (q.includes('রাজবাড়ী') || q.includes('rajbari') || q.includes('জেলা')) {
      responseText = "রাজবাড়ী জেলা বাংলাদেশের ঢাকা বিভাগের একটি প্রশাসনিক অঞ্চল। এটি পদ্মা নদীর তীরে অবস্থিত এবং সাহিত্যিক মীর মশাররফ হোসেনের জন্মস্থান হিসেবে এটি বিখ্যাত। বর্তমানে এটি একটি উদীয়মান স্মার্ট জেলা।";
    }
    // 7. Greetings
    else if (q.includes('হাই') || q.includes('হ্যালো') || q.includes('কেমন আছ') || q.includes('hi') || q.includes('hello')) {
      responseText = "হ্যালো! আমি রাজবাড়ী স্মার্ট এআই-এর পুটার ইঞ্জিন। বর্তমানে জেমিনি এআই-এর সাথে সংযোগ না থাকায় আমি লিমিটেড মোডে কাজ করছি। আপনি কি রাজবাড়ীর ট্রেন, ডাক্তার বা জরুরি কোনো তথ্য খুঁজছেন?";
    }
    // 8. Fallback (If nothing matches)
    else {
      responseText = "দুঃখিত, জেমিনি এআই সংযোগ বিচ্ছিন্ন এবং আপনার প্রশ্নের কোনো সরাসরি উত্তর আমার লোকাল ডাটাবেসে নেই। তবে আমি আপনাকে নিচের বিষয়গুলোতে সাহায্য করতে পারি:\n\n• **ট্রেন সময়সূচী** (লিখুন: ট্রেন)\n• **ডাক্তার তালিকা** (লিখুন: ডাক্তার)\n• **জরুরি নম্বর** (লিখুন: হেল্পলাইন)\n• **বাজারদর** (লিখুন: বাজারদর)";
    }

    return { text: responseText, data: results };
  };

  const handleSend = async (retryText?: string) => {
    const userMessage = retryText || input.trim();
    if (!userMessage || isTyping) return;

    if (!retryText) {
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    }

    setIsTyping(true);

    try {
      const history = messages.map(m => ({ role: m.role, text: m.text }));
      history.push({ role: 'user', text: userMessage });

      const data = await db.callAI({
        contents: history,
        systemInstruction: SYSTEM_INSTRUCTION
      });

      if (data.mode === 'local_fallback' || !data.text) {
        throw new Error("SERVER_UNAVAILABLE");
      }

      setMessages(prev => [...prev, { role: 'model', text: data.text, mode: 'gemini' }]);
    } catch (error: any) {
      console.warn("Gemini Failed. Puter Logic Engaging...");
      const puterResponse = runPuterLocalSearch(userMessage);

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: puterResponse.text, 
        mode: 'puter',
        localData: puterResponse.data
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  const formatText = (text: string) => {
    return text.split('**').map((part, i) => i % 2 === 1 ? <strong key={i} className="font-black text-slate-900 dark:text-white">{part}</strong> : part);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] animate-slide-up relative">
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
            <Sparkles className="w-5 h-5 fill-white" />
          </div>
          <div>
            <h3 className="font-black text-slate-800 dark:text-white leading-none text-sm uppercase tracking-tight">Rajbari Smart AI</h3>
            <div className="flex items-center gap-1.5 mt-1">
              <div className="flex items-center gap-1 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-tighter bg-emerald-100 text-emerald-600 shadow-sm">
                <Globe className="w-2.5 h-2.5" />
                Live Engine
              </div>
            </div>
          </div>
        </div>
        <button 
          onClick={() => setMessages([{ role: 'model', text: 'চ্যাট হিস্টোরি ক্লিয়ার করা হয়েছে। আমি আপনাকে রাজবাড়ী সম্পর্কে নতুনভাবে কীভাবে সাহায্য করতে পারি?', mode: 'gemini' }])} 
          className="p-3 text-slate-400 hover:text-rose-500 rounded-xl transition-colors active:scale-90"
        >
          <Trash2 className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-8 bg-slate-50 dark:bg-slate-950">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[92%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 shadow-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-800 text-indigo-600 border border-slate-100 dark:border-slate-800'}`}>
                {msg.role === 'user' ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
              </div>
              <div className="flex flex-col gap-1.5">
                {msg.role === 'model' && (
                   <span className={`text-[8px] font-black uppercase tracking-widest flex items-center gap-1 mb-1 px-2 py-0.5 rounded-full w-fit ${msg.mode === 'gemini' ? 'bg-indigo-50 text-indigo-500' : 'bg-amber-100 text-amber-600'}`}>
                     {msg.mode === 'gemini' ? <Sparkles className="w-2 h-2" /> : <Cpu className="w-2 h-2" />}
                     {msg.mode === 'gemini' ? 'Gemini AI Online' : 'Puter Local Engine'}
                   </span>
                )}
                <div className={`p-4 rounded-[1.8rem] text-sm leading-relaxed whitespace-pre-line shadow-sm border ${
                  msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none border-indigo-600' 
                  : msg.mode === 'puter' 
                    ? 'bg-amber-50 dark:bg-amber-950/20 text-amber-900 dark:text-amber-200 border-amber-200 dark:border-amber-900 rounded-tl-none'
                    : 'bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-200 rounded-tl-none border-slate-100 dark:border-slate-800'
                }`}>
                  {formatText(msg.text)}

                  {msg.localData && msg.localData.length > 0 && (
                    <div className="mt-4 space-y-2">
                      {msg.localData.slice(0, 4).map((item, i) => (
                        <div key={i} className="bg-white/50 dark:bg-black/20 p-3 rounded-xl border border-white/20 flex justify-between items-center transition-all active:scale-95">
                          <div className="flex items-center gap-2">
                            {item.route ? <TrainFront className="w-3.5 h-3.5 text-indigo-600" /> : <User className="w-3.5 h-3.5 text-indigo-600" />}
                            <div className="flex flex-col">
                                <span className="text-[11px] font-black text-slate-800 dark:text-white">{item.name}</span>
                                <span className="text-[8px] text-slate-400 font-bold uppercase">{item.specialty || item.route || item.type}</span>
                            </div>
                          </div>
                          {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><Phone className="w-3.5 h-3.5" /></a>}
                        </div>
                      ))}
                      <p className="text-[9px] opacity-60 italic text-center mt-2 font-bold uppercase tracking-widest flex items-center justify-center gap-2">
                         {/* Correctly imported Info icon */}
                         <Info className="w-3 h-3" /> More data in Main Menu
                      </p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start items-center gap-3">
            <div className="w-8 h-8 rounded-xl bg-white dark:bg-slate-800 flex items-center justify-center text-indigo-600 shadow-sm border border-slate-100 dark:border-slate-800"><Bot className="w-4 h-4" /></div>
            <div className="bg-white dark:bg-slate-900 px-4 py-3 rounded-2xl border border-slate-100 dark:border-slate-800 flex gap-1 shadow-sm">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-6 bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-800">
        <div className="flex gap-3 bg-slate-50 dark:bg-slate-900 p-2 rounded-[2rem] border border-slate-200 dark:border-slate-800 focus-within:border-indigo-400 transition-all shadow-inner">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="রাজবাড়ী সম্পর্কে জিজ্ঞাসা করুন..." 
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-4 text-slate-800 dark:text-white"
          />
          <button 
            onClick={() => handleSend()}
            disabled={!input.trim() || isTyping}
            className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
              !input.trim() || isTyping ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 text-white shadow-lg active:scale-90 hover:bg-indigo-700'
            }`}
          >
            {isTyping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>
        <div className="mt-3 flex items-center justify-center gap-2 opacity-30">
           <Heart className="w-3 h-3 text-rose-500 fill-rose-500" />
           <span className="text-[8px] font-black uppercase tracking-[0.4em]">Designed for Rajbari</span>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import { GoogleGenAI } from "@google/genai";
import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  extractJSON: (text: string | undefined) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string;
    useSearch?: boolean;
  }) => {
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey || apiKey === "undefined" || apiKey === "") {
        throw new Error("API_KEY_MISSING");
      }

      // Initializing strictly as per guidelines
      const ai = new GoogleGenAI({ apiKey });

      let formattedContents: any[];
      if (typeof params.contents === 'string') {
        formattedContents = [{ role: 'user', parts: [{ text: params.contents }] }];
      } else if (Array.isArray(params.contents)) {
        formattedContents = params.contents.map((msg: any) => ({
          role: msg.role === 'model' ? 'model' : 'user',
          parts: [{ text: msg.text || "" }]
        }));
      } else {
        formattedContents = [params.contents];
      }

      const enhancedSystemInstruction = params.systemInstruction || `
        আপনি "Rajbari Live Tracker", রাজবাড়ী জেলার ডিজিটাল রেলওয়ে এক্সপার্ট।
        আপনার কাজ হলো ২০২৬ সালের গুগল সার্চ রেজাল্ট এবং রাজবাড়ী ট্রেন ট্র্যাকিং ফেসবুক গ্রুপ থেকে তথ্য নিয়ে সঠিক উত্তর দেওয়া।
        সবসময় ট্রেনের বর্তমান অবস্থান এবং সম্ভাব্য দেরি (Delay) খুঁজে বের করুন।
      `;

      // Using the recommended model for search grounding
      const modelName = 'gemini-3-flash-preview';

      const response = await ai.models.generateContent({
        model: modelName,
        contents: formattedContents,
        config: {
          systemInstruction: enhancedSystemInstruction,
          tools: params.useSearch ? [{ googleSearch: {} }] : undefined,
          temperature: 0.2,
        },
      });

      if (!response || !response.text) {
        throw new Error("EMPTY_RESPONSE");
      }

      // Extracting grounding chunks (URLs) for tracking source
      const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
        title: chunk.web?.title || "সূত্র",
        uri: chunk.web?.uri || "#"
      })).filter((s: any) => s.uri !== "#") || [];

      return {
        text: response.text,
        mode: params.useSearch ? 'gemini_search_live' : 'puter_local_ai',
        sources: sources,
        groundingMetadata: response.candidates?.[0]?.groundingMetadata
      };
    } catch (error: any) {
      console.error("AI Bridge Error:", error.message);
      return {
        text: null,
        mode: 'local_fallback',
        error: error.message
      };
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

